function unescapeText(text) {
  return String(text || '').replace(/\\([_*[\]()~`>#+\-=|{}.!\\])/g, '$1');
}

function resilientJsonParse(str) {
  if (!str || typeof str !== 'string') return null;
  try {
    const m = str.match(/\{[\s\S]*\}/);
    if (m) return JSON.parse(m[0]);
  } catch(e) {}
  try {
    const corrected = str.replace(/,\s*([}\]])/g, '$1');
    return JSON.parse(corrected);
  } catch(e) {}
  return null;
}

const item = items[0];
const llmOutput = item?.json?.output;

if (!llmOutput) {
  return [{
    json: {
      tool_calls: [{
        tool_name: 'answer_user',
        tool_input: {
          message: 'I am having trouble processing that. Please try again.',
          chat_id: item?.json?.chat_id || ''
        }
      }]
    }
  }];
}

const cleanedStr = llmOutput.trim()
  .replace(/```[\w]*\n?/g, '')
  .replace(/```/g, '');

const parsedJson = resilientJsonParse(cleanedStr);

if (parsedJson && parsedJson.tool_calls && Array.isArray(parsedJson.tool_calls)) {
  const processedCalls = parsedJson.tool_calls.map(toolCall => {
    if (toolCall.tool_input?.message) {
      toolCall.tool_input.message = unescapeText(toolCall.tool_input.message);
    }
    return toolCall;
  });
  return [{ json: { tool_calls: processedCalls } }];
} else {
  return [{
    json: {
      tool_calls: [{
        tool_name: 'answer_user',
        tool_input: {
          message: 'My apologies, I could not understand that. Could you rephrase?',
          chat_id: ''
        }
      }]
    }
  }];
}

const raw = $json.confirmation_message 
  || $json.tool_input?.message 
  || $json.text_to_send;

const chatId = $json.chat_id 
  || $json.tool_input?.chat_id 
  || $('Edit Fields').first().json.chat_id;

return [{
  json: {
    text_to_send: raw,
    chat_id_to_use: chatId
  }
}];

